    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -278,7 +278,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	// that are disabled, etc. Terraform's static validation leans towards
