    "file": "internal/terraform/evaluate.go",
    "line": 535,
    "severity": "critical",
    "description": "GetResource deferred instance check inverts the unknown keys logic. It checks '!hasUnknownKeys' instead of 'hasUnknownKeys', so the early return for unknown deferred resources only triggers when keys ARE known. When resource instance keys are unknown (deferred resources), the function should return DynamicVal but instead continues to process invalid state, causing potential panics or incorrect resource values.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -532,7 +532,7 @@ func (d *evaluationStateData) GetResource(addr addrs.Resource, rng tfdiags.Sourc
 	// result for _all_ of its work, rather than continuing to duplicate a bunch
 	// of the logic we've tried to encapsulate over ther already.
 	if d.Operation == walkPlan || d.Operation == walkApply {
